## handleDelete/handleRenameとuseFileTabs連携
```typescript
// WorktreeDetailRefactored.tsx の handleDelete拡張
const handleDelete = useCallback(async (path: string) => {
  // ...既存処理...
  // 成功後: タブも閉じる
  fileTabs.onFileDeleted(path);
  // ...既存のeditorFilePath処理...
}, [worktreeId, fileTabs, ...]);

// WorktreeDetailRefactored.tsx の handleRename拡張
const handleRename = useCallback(async (path: string) => {
  // ...既存処理...
  // 成功後: タブのパス更新
  const newPath = path.replace(currentName, newName);
  fileTabs.onFileRenamed(path, newPath);
}, [worktreeId, fileTabs, ...]);
```
として設計書に追記する。

