```typescript
interface FilePanelContentProps {
  tab: FileTab;
  worktreeId: string;
  onLoadContent: (path: string, content: FileContent) => void;
  onLoadError: (path: string, error: string) => void;
  onSetLoading: (path: string, loading: boolean) => void;
  onEditMarkdown?: (path: string) => void;
}
```
